    <style>

        html { scroll-behavior: smooth; }

        

        /* Animasi Fade In Up */

        @keyframes fadeInUp {

            from {

                opacity: 0;

                transform: translateY(30px);

            }

            to {

                opacity: 1;

                transform: translateY(0);

            }

        }

        

        /* Animasi Fade In Left */

        @keyframes fadeInLeft {

            from {

                opacity: 0;

                transform: translateX(-30px);

            }

            to {

                opacity: 1;

                transform: translateX(0);

            }

        }

        

        /* Animasi Fade In Right */

        @keyframes fadeInRight {

            from {

                opacity: 0;

                transform: translateX(30px);

            }

            to {

                opacity: 1;

                transform: translateX(0);

            }

        }

        

        /* Animasi Bounce */

        @keyframes bounce {

            0%, 20%, 50%, 80%, 100% {

                transform: translateY(0);

            }

            40% {

                transform: translateY(-10px);

            }

            60% {

                transform: translateY(-5px);

            }

        }

        

        /* Animasi Pulse */

        @keyframes pulse {

            0% {

                transform: scale(1);

            }

            50% {

                transform: scale(1.05);

            }

            100% {

                transform: scale(1);

            }

        }

        

        /* Animasi Slide In */

        @keyframes slideIn {

            from {

                opacity: 0;

                transform: translateY(100px);

            }

            to {

                opacity: 1;

                transform: translateY(0);

            }

        }

                opacity: 0;

            }

        }



        .animate-slide-in {

            animation: slideIn 0.3s ease-out;

        }



        .animate-slide-out {

            animation: slideOut 0.3s ease-out;

        }



        .modal-backdrop {

            backdrop-filter: blur(4px);

        }



        .notification-enter {

            animation: slideIn 0.3s ease-out;

        }



        .notification-exit {

            animation: slideOut 0.3s ease-out;

        }

        .carousel-track { display: flex; gap: 2rem; transition: transform 0.5s ease-in-out; }

        .carousel-item { min-width: 320px; flex-shrink: 0; }

        .carousel-btn {

            position: absolute; top: 50%; transform: translateY(-50%);

            background-color: rgba(139, 0, 0, 0.8); color: white; border: none;

            width: 50px; height: 50px; border-radius: 50%; cursor: pointer;

            font-size: 24px; display: flex; align-items: center; justify-content: center;

            z-index: 10; transition: all 0.3s ease;

        }

        .carousel-btn:hover { background-color: rgba(139, 0, 0, 1); transform: translateY(-50%) scale(1.1); }

        .carousel-btn.prev { left: 10px; }

        .carousel-btn.next { right: 10px; }

        .contact-icon { transition: transform 0.3s ease; }

        .contact-icon:hover { transform: scale(1.1) rotate(5deg); }

        .fade-up {

            opacity: 1;

            transform: translateY(0);

            transition: opacity 0.6s ease, transform 0.6s ease;

        }

        .js .fade-up {

            opacity: 0;

            transform: translateY(30px);

        }

        .fade-up.visible {

            opacity: 1;

            transform: translateY(0);

        }

        .halal-intro {

            opacity: 1;

            transform: translateY(0) scale(1);

            transition: opacity 1.2s cubic-bezier(0.16, 1, 0.3, 1), transform 1.2s cubic-bezier(0.16, 1, 0.3, 1);

            will-change: transform, opacity;

        }

        .js .halal-intro {

            opacity: 0;

            transform: translateY(80px) scale(0.965);

        }

        .halal-intro.visible {

            opacity: 1;

            transform: translateY(0) scale(1);

        }

        .halal-logo,

        .halal-desc {

            opacity: 0;

            transform: translateY(34px) scale(0.985);

            transition: opacity 1s cubic-bezier(0.16, 1, 0.3, 1), transform 1s cubic-bezier(0.16, 1, 0.3, 1);

            will-change: transform, opacity;

        }

        .halal-intro.visible .halal-logo,

        .halal-intro.visible .halal-desc {

            opacity: 1;

            transform: translateY(0) scale(1);

        }

        .halal-intro.visible .halal-logo {

            transition-delay: 0.12s;

        }

        .halal-intro.visible .halal-desc {

            transition-delay: 0.34s;

        }

        .rekomendasi-slider {

            position: relative;

            width: 100vw;

            left: 50%;

            right: 50%;

            margin-left: -50vw;

            margin-right: -50vw;

            padding: 1rem 0;

        }



        .rekomendasi-viewport {

            overflow: hidden;

            margin: 0 auto;

            width: 100%;

            max-width: none;

            padding: 0.5rem 0;

        }



        .rekomendasi-track {

            display: flex;

            align-items: stretch;

            gap: 1.5rem;

            width: max-content;

            transition: transform 1.15s cubic-bezier(0.25, 0.46, 0.45, 0.94);

            will-change: transform;

        }



        .rekomendasi-item {

            flex: 0 0 240px;

            padding: 0;

            display: flex;

            opacity: 0.35;

            transition: opacity 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);

        }

        

        .rekomendasi-item.active-card {

            opacity: 1;

        }



        .rekomendasi-item > div {

            width: 100%;

        }



        @media (min-width: 640px) {

