            color: #8f1e14;

            transition: transform 0.25s ease, background-color 0.25s ease;

            flex-shrink: 0;

        }



        .rekomendasi-card:hover .rekomendasi-link {

            transform: translateX(2px);

            background: #ffe7d8;

        }







        .influencer-media::after {

            content: '';

            position: absolute;

            left: 0;

            right: 0;

            bottom: 0;

            height: 45%;

            background: linear-gradient(to top, rgba(0, 0, 0, 0.32), rgba(0, 0, 0, 0));

            pointer-events: none;

        }



        .influencer-play {

            position: absolute;

            left: 50%;

            top: 50%;

            transform: translate(-50%, -50%);

            width: 46px;

            height: 46px;

            border-radius: 999px;

            background: rgba(255, 255, 255, 0.9);

            color: #b42318;

            display: flex;

            align-items: center;

            justify-content: center;

            font-size: 0.95rem;

            box-shadow: 0 8px 16px rgba(0, 0, 0, 0.18);

            transition: transform 0.3s ease, background-color 0.3s ease, color 0.3s ease;

        }



        .influencer-badge {

            position: absolute;

            top: 12px;

            left: 12px;

            background: #b42318;

            color: #fff;

            font-size: 0.68rem;

            font-weight: 700;

            letter-spacing: 0.03em;

            padding: 0.35rem 0.65rem;

            border-radius: 999px;

            max-width: 82%;

            white-space: nowrap;

            overflow: hidden;

            text-overflow: ellipsis;

        }



        .influencer-cta {

            display: inline-flex;

            align-items: center;

            justify-content: center;

            gap: 0.45rem;

            background: #b42318;

            color: #fff;

            font-size: 0.72rem;

            font-weight: 700;

            letter-spacing: 0.03em;

            padding: 0.58rem 1.1rem;

            border-radius: 999px;

            transition: transform 0.25s ease, background-color 0.25s ease, box-shadow 0.25s ease;

            box-shadow: 0 8px 16px rgba(180, 35, 24, 0.28);

        }



        .influencer-cta .external-icon {

            font-size: 0.68rem;

            opacity: 0.9;

            transform: translateY(0);

            transition: transform 0.25s ease, opacity 0.25s ease;

        }



        .influencer-meta {

            margin-top: 1rem;

            display: flex;

            justify-content: center;

            flex-wrap: wrap;

            gap: 0.65rem;

        }



        .influencer-stat {

            display: inline-flex;

            align-items: center;

            gap: 0.5rem;

            background: rgba(180, 35, 24, 0.06);

            border-radius: 999px;

            padding: 0.35rem 0.75rem;

            font-size: 0.78rem;

            font-weight: 600;

            color: #5a1f18;

        }











        @media (prefers-reduced-motion: reduce) {

            .influencer-media,

            .influencer-media img,

            .influencer-play,

