    <script>

        // Filter Menu

        document.querySelectorAll('.filter-btn').forEach(button => {

            button.addEventListener('click', function() {

                const filter = this.dataset.filter;

                

                // Update active button

                document.querySelectorAll('.filter-btn').forEach(btn => {

                    btn.classList.remove('active', 'bg-red-600', 'text-white');

                    btn.classList.add('bg-gray-300', 'text-gray-700');

                });

                this.classList.add('active', 'bg-red-600', 'text-white');

                

                // Show loading state

                const menuContainer = document.getElementById('menuContainer');

                menuContainer.innerHTML = '<div class="col-span-full text-center py-8"><i class="fas fa-spinner fa-spin text-3xl text-red-600"></i><p class="mt-4 text-gray-600">Memuat menu...</p></div>';

                

                // Ajax filter

                fetch(`/filter-menu?category=${filter}`)

                    .then(response => response.json())

                    .then(data => {

                        menuContainer.innerHTML = data.html;

                        

                        // Add fade-in animation to new items

                        const items = menuContainer.querySelectorAll('.menu-item');

                        items.forEach((item, index) => {

                            item.style.opacity = '0';

                            item.style.transform = 'translateY(20px)';

                            setTimeout(() => {

                                item.style.transition = 'opacity 0.5s ease, transform 0.5s ease';

                                item.style.opacity = '1';

                                item.style.transform = 'translateY(0)';

                            }, index * 100);

                        });

                    })

                    .catch(error => {

                        console.error('Error:', error);

                        menuContainer.innerHTML = '<div class="col-span-full text-center py-8 text-red-600"><i class="fas fa-exclamation-triangle text-3xl"></i><p class="mt-4">Terjadi kesalahan saat memuat menu</p></div>';

                    });

            });

        });



        // ========== FUNGSI PAKET ==========

        function pilihPaket(paketType) {

            // Redirect to package detail page

            window.location.href = `/paket/${paketType.toLowerCase()}`;

        }



        function bukaModalOrder() {

            const modal = document.getElementById('modalOrder');

            if (!modal) return;

            modal.classList.remove('hidden');

            modal.classList.add('flex');

        }



        function tutupModalOrder() {

            const modal = document.getElementById('modalOrder');

            if (!modal) return;

            modal.classList.add('hidden');

            modal.classList.remove('flex');

        }



        function showLoginModal() {

            window.location.href = '{{ route('user.login') }}';

        }



        let packageName = '';

        const orderData = { nama: '' };



        function addPaketToCart(paketId) {

            @auth

            const token = document.querySelector('meta[name="csrf-token"]')?.getAttribute('content');

            fetch('{{ route('cart.add') }}', {

                method: 'POST',

                headers: {

                    'Content-Type': 'application/json',

                    'X-CSRF-TOKEN': token,

                    'Accept': 'application/json'

                },

                body: JSON.stringify({

                    type: 'paket',

                    id: paketId,

                    quantity: 1,

                })

            })

                .then(async (res) => {

                    if (!res.ok) {

                        throw new Error('Gagal menambahkan ke keranjang');

                    }

                    return await res.json();

                })

                .then(() => {

                    updateCartCount();

                    showNotification('Berhasil ditambahkan ke keranjang!', 'success');

                })

                .catch(() => {

                    showNotification('Gagal menambahkan ke keranjang', 'error');

                });

            @else

            showLoginModal();

            @endauth

        }



        function addToCartFromPackage(paketName) {

            packageName = paketName;

            orderData.nama = paketName;



            @auth

            bukaModalOrder();

            @else

            showLoginModal();

            @endauth

        }



        function addToCartByName(itemName) {

            console.log('addToCartByName:', itemName);

        }



        // ========== FUNGSI KERANJANG ==========

        function addToCart(menuItemId) {

            console.log('addToCart called with menuItemId:', menuItemId);

            

            // Check if user is authenticated

            @auth

            console.log('User is authenticated');

            // User is authenticated, proceed to add to cart

            @else

            console.log('User is not authenticated, showing login modal');

            // User is not authenticated, show login modal

            showLoginModal();

            return;

            @endauth

            

            // Open modal for authenticated users

            console.log('Opening add to cart modal');

            document.getElementById('modalMenuItemId').value = menuItemId;

            document.getElementById('addToCartModal').classList.remove('hidden');

            document.getElementById('modalQuantity').value = 1;

            document.getElementById('modalNotes').value = '';

            

            // Focus input for better UX

            setTimeout(() => {

                document.getElementById('modalQuantity')?.focus();

            }, 100);

        }



        function showAddToCartModal(menuItemId) {

            document.getElementById('modalMenuItemId').value = menuItemId;

            document.getElementById('modalQuantity').value = 1;

            document.getElementById('modalNotes').value = '';

            document.getElementById('addToCartModal').classList.remove('hidden');

            // Focus input for better UX

            setTimeout(() => {

                document.getElementById('modalQuantity')?.focus();

            }, 100);

        }



        function closeAddToCartModal() {

            document.getElementById('addToCartModal').classList.add('hidden');

            document.getElementById('addToCartForm').reset();

        }



        function showNotification(message, type = 'success') {

            // Buat elemen notifikasi

            const notification = document.createElement('div');

            notification.className = `fixed bottom-4 right-4 ${type === 'success' ? 'bg-green-600' : 'bg-red-600'} text-white px-6 py-3 rounded-lg shadow-lg z-50 transform transition-all duration-300`;

            notification.innerHTML = `

                <div class="flex items-center">

                    <i class="fas ${type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle'} mr-2"></i>

                    <span>${message}</span>

                </div>

            `;

            

            document.body.appendChild(notification);

            

            // Hapus otomatis setelah 3 detik

            setTimeout(() => {

                notification.remove();

            }, 3000);

        }



        function changeBackground(index) {

            const bg1 = document.getElementById('bg1');

            const bg2 = document.getElementById('bg2');

            const dot1 = document.getElementById('dot1');

            const dot2 = document.getElementById('dot2');

            if (!bg1 || !bg2 || !dot1 || !dot2) return;



            if (index === 1) {

                bg1.classList.remove('opacity-0');

                bg1.classList.add('opacity-100');

                bg2.classList.remove('opacity-100');

                bg2.classList.add('opacity-0');

                dot1.classList.replace('bg-white/40', 'bg-white/80');

                dot2.classList.replace('bg-white/80', 'bg-white/40');

            } else {

                bg2.classList.remove('opacity-0');

                bg2.classList.add('opacity-100');

                bg1.classList.remove('opacity-100');

                bg1.classList.add('opacity-0');

                dot2.classList.replace('bg-white/40', 'bg-white/80');

                dot1.classList.replace('bg-white/80', 'bg-white/40');

            }

        }









        function updateCartCount() {

            fetch('/api/cart-count')

                .then(response => response.json())

                .then(data => {

                    const cartCount = document.getElementById('cartCount');

                    if (cartCount) {

                        cartCount.textContent = data.count;

                    }

                });

        }



        function pesanKeGofood() {

            alert(`Pesan ${orderData.nama} via Gofood\n\nAnda akan diarahkan ke aplikasi Gofood untuk menyelesaikan pesanan.`);

            window.open('https://gofood.co.id', '_blank');

