        // Tutup modal

        const modalOrderEl = document.getElementById('modalOrder');

        if (modalOrderEl) {

            modalOrderEl.addEventListener('click', function(e) {

                if (e.target === this) {

                    tutupModalOrder();

                }

            });

        }



        // ========== AUTO GESER REKOMENDASI (LOOP MULUS) & SWIPE MANUAL ==========

        function initRecommendedAutoScroll() {

            const slider = document.getElementById('rekomendasiSlider');

            const track = document.getElementById('rekomendasiTrack');

            const prevBtn = document.getElementById('rekomPrev');

            const nextBtn = document.getElementById('rekomNext');

            if (!slider || !track || !prevBtn || !nextBtn) return;



            const originalItems = Array.from(track.querySelectorAll('.rekomendasi-item'));

            if (originalItems.length <= 1) return;



            if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {

                return;

            }



            let loopWidth = 0;

            let stepWidth = 0;

            let currentGap = 24;

            let currentCenterOffset = 0;

            const clonesCount = originalItems.length;

            let currentIndex = clonesCount;

            let isAnimating = false;

            let resumeTimer = null;

            let pauseOnHover = false;

            const slideStep = 1;

            const slidePause = 4000;

            const transitionDuration = 1000;

            
            // Swipe state
            let startX = 0;
            let currentX = 0;
            let isDragging = false;
            let dragStartTime = 0;



            track.style.transform = 'translateX(0)';



            function clearClones() {

                track.innerHTML = '';

            }



            function updateActiveCard() {

                const items = track.querySelectorAll('.rekomendasi-item');

                items.forEach((item, idx) => {

                    if (idx === currentIndex) {

                        item.classList.add('active-card');

                    } else {

                        item.classList.remove('active-card');

                    }

                });

            }



            function rebuild() {

                clearClones();

                

                for (let i = 0; i < clonesCount; i++) {

                    const clone = originalItems[i].cloneNode(true);

                    clone.setAttribute('data-reko-clone', 'pre');

                    track.appendChild(clone);

                }



                originalItems.forEach(item => {

                    track.appendChild(item.cloneNode(true));

                });

                

                for (let i = 0; i < clonesCount; i++) {

                    const clone = originalItems[i].cloneNode(true);

                    clone.setAttribute('data-reko-clone', 'post');

                    track.appendChild(clone);

                }



                const gap = parseFloat(getComputedStyle(track).columnGap || getComputedStyle(track).gap || '24') || 24;

                const first = track.querySelector('.rekomendasi-item');

                stepWidth = first ? (first.offsetWidth + gap) : 344;



                // Cache gap and centerOffset for consistent goTo calculations

                currentGap = gap;

                const viewportWidth = window.innerWidth;

                currentCenterOffset = (viewportWidth - (stepWidth - currentGap)) / 2;



                loopWidth = stepWidth * originalItems.length;

                currentIndex = clonesCount;

                track.style.transition = 'none';

                track.style.transform = `translateX(${currentCenterOffset - (currentIndex * stepWidth)}px)`;

                updateActiveCard();

                void track.offsetWidth;

                track.style.transition = `transform ${transitionDuration}ms cubic-bezier(0.25, 0.46, 0.45, 0.94)`;

            }



            function goTo(index, immediate = false) {

                if (stepWidth <= 0) return;



                track.style.transition = immediate ? 'none' : `transform ${transitionDuration}ms cubic-bezier(0.25, 0.46, 0.45, 0.94)`;

                track.style.transform = `translateX(${currentCenterOffset - (index * stepWidth)}px)`;



                if (!immediate) {

                    updateActiveCard();

                }

            }



            function scheduleNextStep() {

                clearTimeout(resumeTimer);

                resumeTimer = setTimeout(() => {

                    if (pauseOnHover || isAnimating || loopWidth <= 0 || isDragging) {

                        scheduleNextStep();

                        return;

                    }

                    next();

                }, slidePause);

            }



            function next() {

                if (isAnimating) return;

                isAnimating = true;

                currentIndex += slideStep;

                goTo(currentIndex);



                if (currentIndex >= clonesCount * 2) {

                    setTimeout(() => {

                        currentIndex -= originalItems.length;

                        goTo(currentIndex, true);

                        isAnimating = false;

                        scheduleNextStep();

                    }, transitionDuration);

                } else {

                    setTimeout(() => {

                        isAnimating = false;

                        scheduleNextStep();

                    }, transitionDuration);

                }

            }



            function prev() {

                if (isAnimating) return;

                isAnimating = true;

                currentIndex -= slideStep;

                goTo(currentIndex);



                if (currentIndex < clonesCount) {

                    setTimeout(() => {

                        currentIndex += originalItems.length;

                        goTo(currentIndex, true);

                        isAnimating = false;

                        scheduleNextStep();

                    }, transitionDuration);

                } else {

                    setTimeout(() => {

                        isAnimating = false;

                        scheduleNextStep();

                    }, transitionDuration);

                }

            }
            
            // Mouse & Touch events for manual sliding
            
            function handleDragStart(e) {
                if (isAnimating) return;
                isDragging = true;
                pauseOnHover = true;
                clearTimeout(resumeTimer);
                startX = e.type.includes('mouse') ? e.pageX : e.touches[0].clientX;
                currentX = startX;
                dragStartTime = Date.now();
                track.style.transition = 'none';
            }

            function handleDragMove(e) {
                if (!isDragging) return;
                e.preventDefault();
                currentX = e.type.includes('mouse') ? e.pageX : e.touches[0].clientX;
                const diffX = currentX - startX;
                
                // Add resistive pull at the ends, though cloning means it mostly feels endless
                track.style.transform = `translateX(${currentCenterOffset - (currentIndex * stepWidth) + diffX}px)`;
            }

            function handleDragEnd() {
                if (!isDragging) return;
                isDragging = false;
                pauseOnHover = false;
                
                const diffX = currentX - startX;
                const timeDiff = Date.now() - dragStartTime;
                
                // If swiped far enough or fast enough
                if (Math.abs(diffX) > stepWidth / 3 || (Math.abs(diffX) > 30 && timeDiff < 300)) {
                    if (diffX > 0) {
                        prev();
                    } else {
                        next();
                    }
                } else {
                    // Snap back
                    goTo(currentIndex);
                }
                
                scheduleNextStep();
            }

            slider.addEventListener('mousedown', handleDragStart);
            window.addEventListener('mousemove', handleDragMove);
            window.addEventListener('mouseup', handleDragEnd);

            slider.addEventListener('touchstart', handleDragStart, {passive: true});
            slider.addEventListener('touchmove', handleDragMove, {passive: false});
            slider.addEventListener('touchend', handleDragEnd);



            slider.addEventListener('mouseenter', () => {

                pauseOnHover = true;

            });



            slider.addEventListener('mouseleave', () => {

                if (!isDragging) {
                    pauseOnHover = false;

                    scheduleNextStep();
                }

            });



            slider.addEventListener('focusin', () => {

                pauseOnHover = true;

            });



            slider.addEventListener('focusout', () => {

                pauseOnHover = false;

                scheduleNextStep();

            });



            prevBtn.addEventListener('click', () => {

                if (loopWidth <= 0 || isAnimating) return;

                clearTimeout(resumeTimer);

                prev();

            });



            nextBtn.addEventListener('click', () => {

                if (loopWidth <= 0 || isAnimating) return;

                clearTimeout(resumeTimer);

                next();

            });



            window.addEventListener('resize', rebuild);



            rebuild();

            scheduleNextStep();

        }



        initRecommendedAutoScroll();



        // ========== FADE UP ANIMATION ==========

        const revealEls = document.querySelectorAll('.fade-up, .fade-left, .fade-right');

        if (revealEls.length > 0) {

            if ('IntersectionObserver' in window) {

                const observerOptions = {

                    threshold: 0.12,

                    rootMargin: '0px 0px -60px 0px'

                };



                const observer = new IntersectionObserver((entries) => {

                    entries.forEach(entry => {

                        if (entry.isIntersecting) {

                            entry.target.classList.add('visible');

                            observer.unobserve(entry.target);

                        }

                    });

                }, observerOptions);



                revealEls.forEach(el => observer.observe(el));

            } else {

                revealEls.forEach(el => el.classList.add('visible'));

            }

        }



        // ========== PHOTO HOVER EFFECT ==========

        const imgs = document.querySelectorAll('img');

        imgs.forEach(img => {

            if (img.closest('header')) return;

            if (img.closest('footer')) return;

            if (img.classList.contains('no-photo-hover')) return;

            img.classList.add('photo-hover');

        });

    </script>

</body>

</html>









